examples.original_ir:
define float @test(float %a, float %b) {
entry:
  %cmp = fcmp olt float %a, %b
  %sel = select nnan i1 %cmp, float %a, float %b
  ret float %sel
}

examples.optimized_ir:
define float @test(float %a, float %b) {
entry:
  %cmp = fcmp oge float %a, %b
  %sel = select nnan i1 %cmp, float %b, float %a
  ret float %sel
}
